import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Validate input length
        if (input.length() > 10) {
            System.out.println("Input exceeds maximum length. Please enter a shorter name.");
            return;
        }

        // Copy input to buffer with proper length
        char[] buffer = new char[input.length()];
        input.getChars(0, input.length(), buffer, 0);

        System.out.println("Hello, " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
